15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const PROCESSING_FEE_G = 5;
25	const FIRST_INSURANCE_SURCHARGE_DIVISOR = 10; // 10% surcharge expressed as a divisor (avoids 0.1 float drift)
26	const RUNE_BLOCK_SIZE = 3;
27	const RUNE_BLOCK_PRICE_G = 60;
28	const RUNE_UNIT_PRICE_G = 25;
29	
30	const quotePremium = (items: Item[]): number => {
31	  const runeCount = items.filter((i) => i.type === "rune").length;
32	  const nonRuneBase = items
33	    .filter((i) => i.type !== "rune")
34	    .reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
35	  const runeBase =
36	    runeCount === RUNE_BLOCK_SIZE ? RUNE_BLOCK_PRICE_G : runeCount * RUNE_UNIT_PRICE_G;
37	  const policyBase = nonRuneBase + runeBase;
38	  const withFirstInsuranceSurcharge = policyBase + policyBase / FIRST_INSURANCE_SURCHARGE_DIVISOR;
39	  return Math.ceil(withFirstInsuranceSurcharge + PROCESSING_FEE_G);
40	};
41	
42	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
43	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
44	  return { results };
45	};
